<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bots</title>
<style>
  html, body { margin:0; padding:0; background:#111; color:#eee; font-family: monospace; }
  body { display:flex; flex-direction:column; align-items:center; padding:10px; }
  #info { display:flex; gap:20px; align-items:center; margin-bottom:8px; font-size:16px; }
  #info button { font-family:monospace; font-size:14px; padding:4px 10px; cursor:pointer; }
  #maze { background:#000; display:block; border:1px solid #444; }
  #stats { margin-top:8px; font-size:13px; color:#aaa; }
</style>
</head>
<body>
<div id="info">
  <div>Completed: <span id="completed">0</span> / 24</div>
  <div>Timer: <span id="timer">0</span></div>
  <button id="reset">Reset</button>
</div>
<div id="maze"></div>
<div id="stats">Bots explore via Trémaux/DFS with seeded preferences. Smooth interpolation between cells.</div>

<script>
(function(){
  'use strict';

  // ----- Maze generation: recursive backtracker, seeded RNG -----
  function mulberry32(seed){
    let a = seed >>> 0;
    return function(){
      a |= 0; a = a + 0x6D2B79F5 | 0;
      let t = a;
      t = Math.imul(t ^ t >>> 15, t | 1);
      t ^= t + Math.imul(t ^ t >>> 7, t | 61);
      return ((t ^ t >>> 14) >>> 0) / 4294967296;
    };
  }

  function generateMaze(rows, cols, seed){
    const rng = mulberry32(seed);
    const N=0, E=1, S=2, W=3;
    const OPP = [S,W,N,E];
    const DR = [-1,0,1,0];
    const DC = [0,1,0,-1];

    // walls[r][c] is bitmask of OPENINGS (not walls). Bit i=1 means passage in direction i.
    // Convention: a "wall" between (r,c) and (r+dr,c+dc) exists if neither cell has opening.
    const openings = [];
    for(let r=0;r<rows;r++){
      const row = [];
      for(let c=0;c<cols;c++) row.push(0);
      openings.push(row);
    }

    const visited = [];
    for(let r=0;r<rows;r++){
      const row = [];
      for(let c=0;c<cols;c++) row.push(false);
      visited.push(row);
    }

    const stack = [];
    // Start from a random cell
    const sr = Math.floor(rng()*rows);
    const sc = Math.floor(rng()*cols);
    visited[sr][sc] = true;
    stack.push([sr,sc]);

    while(stack.length>0){
      const [r,c] = stack[stack.length-1];
      // Shuffle directions
      const dirs = [N,E,S,W];
      // Fisher-Yates with rng
      for(let i=dirs.length-1;i>0;i--){
        const j = Math.floor(rng()*(i+1));
        const tmp=dirs[i]; dirs[i]=dirs[j]; dirs[j]=tmp;
      }
      let carved = false;
      for(const d of dirs){
        const nr = r+DR[d], nc = c+DC[d];
        if(nr>=0 && nr<rows && nc>=0 && nc<cols && !visited[nr][nc]){
          // Carve passage
          openings[r][c] |= (1<<d);
          openings[nr][nc] |= (1<<OPP[d]);
          visited[nr][nc] = true;
          stack.push([nr,nc]);
          carved = true;
          break;
        }
      }
      if(!carved){
        stack.pop();
      }
    }

    // Choose spawn and exit at random distant cells (use BFS from spawn to find farthest)
    const spawnR = Math.floor(rng()*rows);
    const spawnC = Math.floor(rng()*cols);
    // BFS
    const dist = [];
    for(let r=0;r<rows;r++){
      const row = [];
      for(let c=0;c<cols;c++) row.push(-1);
      dist.push(row);
    }
    const q = [[spawnR,spawnC]];
    dist[spawnR][spawnC] = 0;
    while(q.length>0){
      const [r,c] = q.shift();
      for(let d=0;d<4;d++){
        if(openings[r][c] & (1<<d)){
          const nr=r+DR[d], nc=c+DC[d];
          if(dist[nr][nc]===-1){
            dist[nr][nc] = dist[r][c]+1;
            q.push([nr,nc]);
          }
        }
      }
    }
    // Find farthest
    let maxD = -1, exitR=spawnR, exitC=spawnC;
    for(let r=0;r<rows;r++){
      for(let c=0;c<cols;c++){
        if(dist[r][c] > maxD){ maxD = dist[r][c]; exitR=r; exitC=c; }
      }
    }
    return { openings, spawn:{r:spawnR,c:spawnC}, exit:{r:exitR,c:exitC} };
  }

  // ----- Bot: Trémaux-style DFS -----
  // Each bot has its own state machine. Direction preference is seeded by bot index + maze seed.
  function createBot(idx, spawn, maze, botSeed){
    const N=0,E=1,S=2,W=3;
    const DR=[-1,0,1,0], DC=[0,1,0,-1];
    const rng = mulberry32(botSeed);
    // Direction order: random rotation of [N,E,S,W]
    const base = [N,E,S,W];
    // shuffle deterministically
    for(let i=base.length-1;i>0;i--){
      const j = Math.floor(rng()*(i+1));
      const tmp=base[i]; base[i]=base[j]; base[j]=tmp;
    }
    // Interleaving with rotations - we'll just always use this fixed preference but with random tie-breaking per step.

    return {
      idx,
      r: spawn.r,
      c: spawn.c,
      // Current sub-path being explored (DFS stack of cells). Start with just the spawn.
      stack: [{r:spawn.r, c:spawn.c}],
      // Track visits per passage to implement Trémaux rule:
      // mark[cell] = count of times each passage entered. Trémaux says a passage is dead when entered 2x.
      // We use a per-cell map: {dir: count}
      marks: {},
      // Mark the entry to spawn cell's previous "incoming" as N/A. We track "incoming direction" to parent in stack.
      incoming: null, // direction we came from to reach the top of stack; null for spawn
      // Path of all cells entered (in order). The bot "enters" spawn first.
      path: [{r:spawn.r, c:spawn.c}],
      // Cells marked as dead-ends by this bot
      deadEnds: [],
      finishTick: null,
      // For smooth rendering: previous cell position (r,c) when moving
      prevR: spawn.r, prevC: spawn.c,
      // Movement progress in ticks (0..1) - we move one cell per tick, so progress resets each tick.
      // For interpolation we use gameTick fractional position.
      done: false,
      // The bot's direction-preference order
      dirOrder: base,
      // A small per-step rng
      rng: mulberry32(botSeed ^ 0x9E3779B9)
    };
  }

  function botStep(bot, maze, tick){
    const N=0,E=1,S=2,W=3;
    const DR=[-1,0,1,0], DC=[0,1,0,-1];
    const OPP = [S,W,N,E];
    const openings = maze.openings;
    const rows = maze.rows, cols = maze.cols;

    if(bot.done) return;

    // Special case: at exit -> done
    if(bot.r === maze.exit.r && bot.c === maze.exit.c){
      if(bot.finishTick === null){
        bot.finishTick = tick;
      }
      bot.done = true;
      return;
    }

    const r = bot.r, c = bot.c;
    const cellMarks = bot.marks[`${r},${c}`] || {};
    // Check available passages
    // Determine which neighbor directions are open
    const openDirs = [];
    for(let d=0;d<4;d++){
      if(openings[r][c] & (1<<d)) openDirs.push(d);
    }

    // Determine candidate next dirs: those open passages whose mark count for THIS direction from current cell is < 2.
    // We use a per-cell, per-direction mark.
    const candidates = [];
    for(const d of openDirs){
      // Don't go back the way we came (incoming) if there's an alternative? Trémaux allows it, but let's allow.
      const key = d;
      const m = cellMarks[key] || 0;
      if(m < 2){
        // Also, we shouldn't immediately backtrack on a freshly-marked passage if alternatives exist - Trémaux style:
        // Actually Trémaux: choose unvisited passage; if none, choose one marked once; if none, retreat.
        // We'll implement: prefer m==0, then m==1.
        candidates.push({d, m});
      }
    }

    // Sort: m==0 first, then by direction preference
    const pref = bot.dirOrder;
    const prefIdx = {};
    for(let i=0;i<pref.length;i++) prefIdx[pref[i]] = i;

    candidates.sort((a,b)=>{
      if(a.m !== b.m) return a.m - b.m;
      return prefIdx[a.d] - prefIdx[b.d];
    });

    // Decide: if any m==0 exists, take the first (in preference). If only m==1, take first. If none, backtrack.
    // But we should also consider: if we're at a dead end (no m==0 candidates AND incoming exists), we backtrack.
    // Actually: if no candidate has m==0 and at least one has m==1, we could still explore forward (going through already-marked-once passage) — but that means entering a partially-explored branch.
    // Trémaux proper: take unvisited corridor; if none, take corridor marked once; if none, backtrack.
    // We'll follow this.

    let action = null; // {type:'move', d} or {type:'backtrack'}
    if(candidates.length > 0 && candidates[0].m === 0){
      action = {type:'move', d: candidates[0].d};
    } else if(candidates.length > 0){
      // m==1 available — but going forward through a once-marked passage is risky; standard Tremaux treats m=1 as still explorable. We'll allow forward into m=1 ONLY if no "backtrack path" alternative exists... Actually classic: go forward into m==1.
      // However, to ensure correctness and to not over-traverse, we'll go forward into m==1.
      action = {type:'move', d: candidates[0].d};
    } else {
      // No candidate: backtrack
      action = {type:'backtrack'};
    }

    // Special handling: dead end. A dead end cell is one where the only passage is the incoming one.
    // When we are AT a dead end and decide to backtrack, we should mark this cell as a dead end in bot.deadEnds.
    // Detect: openDirs has exactly 1, and that direction equals OPP of incoming (i.e., the only way out is back).
    const isDeadEnd = (openDirs.length === 1);
    if(action.type === 'backtrack' && isDeadEnd && !bot._markedDead.has && true){
      // We'll use a set to avoid re-adding
      if(!bot._deadSet) bot._deadSet = {};
      const key = `${r},${c}`;
      if(!bot._deadSet[key]){
        bot._deadSet[key] = true;
        bot.deadEnds.push({r,c});
      }
    } else if(action.type === 'backtrack' && !isDeadEnd){
      // We're at a junction but backtracking because all branches explored - that's not a "dead end" per se but we can still consider it. We'll only mark true dead ends (passages used up).
      // Actually per spec: "when a bot hits a dead end (or a fully explored branch), it BACKTRACKS and records that branch in its own memory as dead"
      // So fully-explored junctions should also be recorded. But we want deadEnds to be cells, not branches. Let's record the current cell when we backtrack from a fully-explored cell too.
      if(!bot._deadSet) bot._deadSet = {};
      const key = `${r},${c}`;
      if(!bot._deadSet[key]){
        bot._deadSet[key] = true;
        bot.deadEnds.push({r,c});
      }
    }

    if(action.type === 'move'){
      const d = action.d;
      const nr = r + DR[d], nc = c + DC[d];
      // Increment mark for this direction from current cell
      const k = `${r},${c}`;
      if(!bot.marks[k]) bot.marks[k] = {};
      bot.marks[k][d] = (bot.marks[k][d] || 0) + 1;
      // Also increment mark on the neighbor cell for OPP[d] direction (entering through it)
      const nk = `${nr},${nc}`;
      if(!bot.marks[nk]) bot.marks[nk] = {};
      bot.marks[nk][OPP[d]] = (bot.marks[nk][OPP[d]] || 0) + 1;
      // Move
      bot.prevR = bot.r; bot.prevC = bot.c;
      bot.r = nr; bot.c = nc;
      bot.incoming = OPP[d];
      bot.stack.push({r:nr, c:nc});
      bot.path.push({r:nr, c:nc});
      // Check exit
      if(nr === maze.exit.r && nc === maze.exit.c){
        if(bot.finishTick === null) bot.finishTick = tick + 1; // arrival at end of this tick? We'll say arrival tick = current tick after move
      }
    } else {
      // Backtrack
      if(bot.stack.length <= 1){
        // Nowhere to backtrack — stuck (shouldn't happen in connected maze). Mark done.
        bot.done = true;
        if(bot.finishTick === null) bot.finishTick = tick;
        return;
      }
      // Pop stack to get previous cell
      const prev = bot.stack[bot.stack.length-2];
      bot.prevR = bot.r; bot.prevC = bot.c;
      bot.r = prev.r; bot.c = prev.c;
      bot.stack.pop();
      // Incoming direction: we don't strictly need to maintain it precisely during backtrack because marks dictate behavior, but let's set it to null (no "parent" within current DFS since we're retreating).
      bot.incoming = null;
    }
  }

  // ----- The Game -----
  const ROWS = 17, COLS = 17;
  const NUM_BOTS = 24;
  const CELL = 26; // pixel size
  let WALL_W = 2;

  const mazeEl = document.getElementById('maze');
  const completedEl = document.getElementById('completed');
  const timerEl = document.getElementById('timer');
  const resetEl = document.getElementById('reset');

  // Canvas
  const canvasW = COLS * CELL + 1;
  const canvasH = ROWS * CELL + 1;
  const canvas = document.createElement('canvas');
  canvas.width = canvasW;
  canvas.height = canvasH;
  canvas.style.display = 'block';
  canvas.style.background = '#000';
  mazeEl.appendChild(canvas);
  const ctx = canvas.getContext('2d');

  // Robot colors - distinct, vibrant
  const BOT_COLORS = [
    '#ff5252','#ff9800','#ffeb3b','#66bb6a','#26c6da','#42a5f5','#7e57c2','#ec407a',
    '#ff6e40','#ffd600','#00e676','#00bcd4','#2196f3','#9c27b0','#e91e63','#795548',
    '#9e9e9e','#607d8b','#f06292','#aed581','#4dd0e1','#7986cb','#ba68c8','#d4e157'
  ];

  const game = {
    seed: 42,
    maze: null,
    bots: [],
    tickCount: 0,
    elapsed: 0,
    frozen: false,
    lastArrivalTick: null,
    rows: ROWS,
    cols: COLS,
    spawn: null,
    exit: null,
    tick: function(n){
      if(n <= 0) return;
      // If frozen, tick does nothing to elapsed or bot positions? Spec: "after that, further ticks must not change the timer or game.elapsed."
      // Bots still done. We should still allow tick to be called but be a no-op effectively.
      if(this.frozen){
        return;
      }
      for(let t=0; t<n; t++){
        // If any bot not done, advance one tick
        let anyActive = false;
        for(let i=0;i<this.bots.length;i++){
          const b = this.bots[i];
          if(!b.done){ anyActive = true; break; }
        }
        if(!anyActive){
          this.frozen = true;
          break;
        }
        this.tickCount++;
        for(let i=0;i<this.bots.length;i++){
          const b = this.bots[i];
          if(b.done) continue;
          botStep(b, this.maze, this.tickCount);
          // If this step caused finish, set lastArrivalTick
          if(b.done && b.finishTick !== null){
            if(this.lastArrivalTick === null || b.finishTick > this.lastArrivalTick){
              this.lastArrivalTick = b.finishTick;
            }
          }
        }
        // Check if all done now
        let allDone = true;
        for(let i=0;i<this.bots.length;i++){
          if(!this.bots[i].done){ allDone = false; break; }
        }
        if(allDone){
          this.elapsed = this.lastArrivalTick;
          this.frozen = true;
          timerEl.textContent = String(this.elapsed);
          completedEl.textContent = String(this.countCompleted());
          break;
        } else {
          this.elapsed = this.tickCount;
        }
      }
      // Update UI
      timerEl.textContent = String(this.elapsed);
      completedEl.textContent = String(this.countCompleted());
    },
    countCompleted: function(){
      let c=0;
      for(let i=0;i<this.bots.length;i++) if(this.bots[i].done) c++;
      return c;
    },
    reset: function(seed){
      if(typeof seed === 'number') this.seed = seed;
      else this.seed = (Math.random()*2**31)|0;
      const m = generateMaze(this.rows, this.cols, this.seed);
      m.rows = this.rows; m.cols = this.cols;
      this.maze = m;
      this.spawn = m.spawn;
      this.exit = m.exit;
      this.bots = [];
      for(let i=0;i<NUM_BOTS;i++){
        const botSeed = (this.seed * 2654435761 ^ (i+1) * 374761393) >>> 0;
        const b = createBot(i, this.spawn, m, botSeed);
        this.bots.push(b);
      }
      this.tickCount = 0;
      this.elapsed = 0;
      this.frozen = false;
      this.lastArrivalTick = null;
      timerEl.textContent = '0';
      completedEl.textContent = '0';
      drawMaze();
      drawBots(0); // initial
    },
    size: function(){ return {rows: this.rows, cols: this.cols}; },
    walls: function(r,c){
      // Return {n,e,s,w} booleans: true means WALL present.
      const o = this.maze.openings[r][c];
      return {
        n: !(o & 1),
        e: !(o & 2),
        s: !(o & 4),
        w: !(o & 8)
      };
    }
  };
  // Expose
  window.game = game;
  game.size = {rows: ROWS, cols: COLS}; // direct property as per spec

  // Override: spec wants game.size as a value {rows,cols}. We'll set it each reset.
  // Actually spec says: window.game.size  // {rows, cols}. So a property. Let's keep as property set in reset.

  // ----- Drawing -----
  function drawMaze(){
    const W = canvas.width, H = canvas.height;
    ctx.fillStyle = '#000';
    ctx.fillRect(0,0,W,H);

    const m = game.maze;
    const op = m.openings;
    // Draw walls
    ctx.strokeStyle = '#e0e0e0';
    ctx.lineWidth = WALL_W;
    ctx.lineCap = 'butt';

    // Outer border always drawn
    ctx.beginPath();
    ctx.rect(0,0,W-1,H-1);
    ctx.stroke();

    // Internal walls: draw a wall between (r,c) and (r+dr,c+dc) if no passage.
    // To avoid double-drawing, only draw N and W walls per cell (plus S of last row, E of last col).
    for(let r=0;r<ROWS;r++){
      for(let c=0;c<COLS;c++){
        const x = c*CELL, y = r*CELL;
        const o = op[r][c];
        // North
        if(r>0 && !(o & 1)){
          ctx.beginPath();
          ctx.moveTo(x, y);
          ctx.lineTo(x+CELL, y);
          ctx.stroke();
        }
        // West
        if(c>0 && !(o & 8)){
          ctx.beginPath();
          ctx.moveTo(x, y);
          ctx.lineTo(x, y+CELL);
          ctx.stroke();
        }
        // South (bottom row)
        if(r === ROWS-1 && !(o & 4)){
          ctx.beginPath();
          ctx.moveTo(x, y+CELL);
          ctx.lineTo(x+CELL, y+CELL);
          ctx.stroke();
        }
        // East (right col)
        if(c === COLS-1 && !(o & 2)){
          ctx.beginPath();
          ctx.moveTo(x+CELL, y);
          ctx.lineTo(x+CELL, y+CELL);
          ctx.stroke();
        }
      }
    }

    // Mark exit with a special cell
    const er = game.exit.r, ec = game.exit.c;
    ctx.fillStyle = '#00ff88';
    ctx.fillRect(ec*CELL + CELL*0.2, er*CELL + CELL*0.2, CELL*0.6, CELL*0.6);
    ctx.fillStyle = '#000';
    ctx.font = (CELL*0.5) + 'px monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('E', ec*CELL + CELL/2, er*CELL + CELL/2 + 1);

    // Mark spawn with subtle indicator
    const sr = game.spawn.r, sc = game.spawn.c;
    ctx.strokeStyle = '#ffeb3b';
    ctx.lineWidth = 2;
    ctx.strokeRect(sc*CELL + 2, sr*CELL + 2, CELL-4, CELL-4);
  }

  // Bots smooth interpolation between cells.
  // We'll animate via requestAnimationFrame. The bot's "logical" position is its current (r,c).
  // It moves to next cell over 1 tick. We track previous cell and use a fraction.
  let animPrevBots = null;
  let animFraction = 0; // 0..1 within current logical tick
  let lastWallTime = performance.now();
  const TICK_MS = 60; // ms per tick for visualization speed

  function snapshotBots(){
    return game.bots.map(b => ({
      r: b.r, c: b.c, prevR: b.prevR, prevC: b.prevC, color: BOT_COLORS[b.idx % BOT_COLORS.length], done: b.done
    }));
  }

  function drawBotsAtFraction(snapshot, frac){
    const radius = CELL*0.28;
    for(const b of snapshot){
      const pr = b.prevR + (b.r - b.prevR) * frac;
      const pc = b.prevC + (b.c - b.prevC) * frac;
      const px = pc * CELL + CELL/2;
      const py = pr * CELL + CELL/2;
      ctx.beginPath();
      ctx.arc(px, py, radius, 0, Math.PI*2);
      ctx.fillStyle = b.color;
      ctx.fill();
      ctx.lineWidth = 1;
      ctx.strokeStyle = '#000';
      ctx.stroke();
    }
  }

  function drawBots(frac){
    const snap = snapshotBots();
    drawBotsAtFraction(snap, frac);
  }

  // Animation loop
  function loop(now){
    const dt = now - lastWallTime;
    lastWallTime = now;
    // Determine if we should advance a logical tick
    // We accumulate time and step game.tick when threshold reached.
    // But game.tick advances simulation. For rendering, we want smooth movement.
    // Approach: keep a target fractional position. Each animation frame, compute fraction = (now - lastTickTime)/TICK_MS.
    // When fraction >= 1, advance game by floor(fraction) ticks and set fraction = fraction%1.
    // However, spec requires tick(n) to be deterministic and synchronous. Our auto-advance via rAF is for visualization; tests will call game.tick directly.
    // We must ensure that auto-advance doesn't conflict with manual ticks. To be safe: ONLY auto-advance when not frozen.
    // And importantly: manual tick(n) should still trigger a redraw.
    // Simplest: don't auto-advance at all. Render bots at their current logical positions without interpolation, OR interpolate based on a virtual clock that doesn't affect logical state.
    // Actually the spec says bots move smoothly (interpolated between cells, not teleporting). So we need interpolation. But the logical state changes per tick.
    // Solution: track last logical tick time; between ticks, interpolate from previous cell to current cell. When a manual tick is called, the "previous" cell becomes the old current cell, and the bot is now at the new cell — we'd see a teleport unless we know the previous.
    // But we DO track prevR/prevC on the bot — set when it moves. So after a manual tick, prevR/prevC is the cell before the move, and r/c is the new cell. Good — we can interpolate from prevR/prevC to r/c at fraction=0 immediately after the tick, then animate to fraction=1 over TICK_MS.
    // So: after each game.tick(n), we reset our interpolation timer: lastTickWallTime = now, fraction=0.
    // And between frames, fraction increases.
    // Let's implement that.
    requestAnimationFrame(loop);
  }

  // Better: separate render loop that interpolates based on time since lastTickWallTime.
  let lastTickWallTime = 0;
  function renderLoop(now){
    if(lastTickWallTime === 0) lastTickWallTime = now;
    const elapsed = now - lastTickWallTime;
    const frac = Math.min(1, elapsed / TICK_MS);
    // Redraw maze (could cache, but fine)
    drawMaze();
    // Draw bots at fraction
    drawBots(frac);
    requestAnimationFrame(renderLoop);
  }

  // When tick is called, reset interpolation
  const origTick = game.tick.bind(game);
  game.tick = function(n){
    origTick(n);
    lastTickWallTime = performance.now();
    // immediate redraw at fraction 0
    drawMaze();
    drawBots(0);
  };

  // Initial reset and start
  function init(){
    game.reset(42);
    requestAnimationFrame(renderLoop);
  }

  resetEl.addEventListener('click', function(){
